    dispatch(fetchDataExpenseChart(other)).unwrap();
  }, [filterDashboard]);

  const groupedData = useMemo(() => {
    if (!dataRevenue) return [];
    const map = {};

    dataRevenue.forEach((item) => {
      map[item.label] = (map[item.label] || 0) + item.data;
    });

    return Object.entries(map).map(([label, total]) => ({
      label,
      total,
    }));
  }, [dataRevenue]);

  const arr = groupedData
    .map((e) => {
      return {
        ...e,
        value: e.total,
      };
    })
    .sort((a, b) => b.value - a.value);

  const total = arr.reduce(
    (accumulator, currentValue) => accumulator + currentValue.value,
    0
  );

  const data = {
    labels: _.map(
      arr,
      (item) => `${item.label}  ${((item.value / total) * 100).toFixed(1)}%`
    ),
    datasets: [
      {
        label: "Chi phí",
        data: _.map(arr, (item) => item.value),
        backgroundColor: colorChartPie.slice(0, groupedData.length),
        borderColor: "#ffffff",
        borderWidth: 1,
      },
    ],
  };

  const options = {
    plugins: {
      legend: {
        position: "right",
      },
    },
  };

  return (
    <div>
      <Pie data={data} options={options} />
    </div>
  );
};

